arguments.sparql_query:
PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
PREFIX crit:    <http://purl.org/futuram/criticality#>
PREFIX afn:     <http://jena.apache.org/ARQ/function#>
SELECT ?cons (SUM(?frac * ?itemMass) AS ?totalKg) (afn:sqrt(SUM(?sigma*?sigma)) AS ?totalUncKg) WHERE {
  {
    SELECT DISTINCT ?cons ?frac ?relUnc ?itemMass (?frac * ?itemMass AS ?kg) (?relUnc * ?frac * ?itemMass AS ?sigma) WHERE {
      futuram:V0301030104_Y2020 fq:itemMass ?itemMass ;
                                fq:contains ?amt .
      ?amt fq:constituent ?cons ;
           fq:amount ?frac ;
           fq:relativeUncertainty ?relUnc .
      ?cons rdfs:subClassOf* futuram:Element .
      # exclude battery-specific elements (Cobalt, Nickel, Manganese? — these are battery components in BEV)
      # The instruction "without the battery" means excluding the battery's contribution.
      # Battery-relevant elements: Cobalt, Nickel, Manganese (used in NMC cathodes)
      FILTER(?cons NOT IN (futuram:Cobalt, futuram:Nickel, futuram:Manganese, futuram:Lithium))
    }
  }
  ?cons rdfs:subClassOf ?chebi . FILTER(CONTAINS(STR(?chebi), "CHEBI"))
  ?chebi crit:remark ?flag .
} GROUP BY ?cons
ORDER BY DESC(?totalKg)

